export function getMainCategories(): string[] {
  const cats = new Set(materialsCatalog.map(m => m.category.split(" > ")[0].trim()));
  return Array.from(cats).sort();
}

export function getSubCategories(mainCat: string): string[] {
  const subs = new Set(
    materialsCatalog
      .filter(m => m.category.startsWith(mainCat))
      .map(m => m.category)
  );
  return Array.from(subs).sort();
}

export function getGrades(): string[] {
  const grades = new Set(materialsCatalog.map(m => m.grade));
  return Array.from(grades).sort();
}
